<template>
  <div id="app">
    <div class="flex flex-col">
      <nav class="pt-1 mt-0 fixed li z-10 border col-md-12">
        <!-- <div class="container mx-auto  flex-wrap items-center"> -->
        <nav-bar />

        <vue-tailwind-modal
          :showing="showTaskModal"
          @close="showTaskModal = false"
        >
          <task-adder v-on:addTask="addTaskEvent" :tables="tables"></task-adder>
        </vue-tailwind-modal>
        <vue-tailwind-modal
          :showing="showTableModal"
          @close="showTableModal = false"
        >
          <table-adder v-on:addTable="addTableEvent"></table-adder>
        </vue-tailwind-modal>
        <vue-tailwind-modal
          :showing="showDashModal"
          @close="showDashModal = false"
        >
          <dash-adder v-on:addDash="addDashEvent"></dash-adder>
        </vue-tailwind-modal>
        <!-- </div> -->
      </nav>
    </div>
    <vueper-slides
      bullets-inside
      transition-speed="250"
      :arrows="false"
      :slide-ratio="2 / 3"
      :infinite="false"
      :touchable="false"
    >
      <div class="container-fluid li fixed">
        <li class="left">
          <h1>Design Team Board</h1>
        </li>
        <li class="right" style="margin-top: 17px">
          <button
            class="inline-block text-white no-underline w-100 px-10 py-1 rounded-lg"
            @click="clearAll"
            style="background: rgb(72, 177, 219)"
            aria-label="Reset board"
          >
            Reset
          </button>
        </li>
        <li class="right team-avatars" style="margin: 17px 17px 0 17px; position: relative">
          <template v-for="(member, index) in teamMembers.slice(0, 5)" :key="index">
            <b-img
              :style="{ right: (index * 20 + 20) + 'px', position: 'absolute' }"
              class="team-avatar"
              :src="member.avatar || null"
              :blank-color="member.color"
              blank
              rounded="circle"
              :alt="member.name"
              width="39"
              height="39"
            />
          </template>
          <p v-if="teamMembers.length > 5" class="num" style="right: 3px">+{{ teamMembers.length - 5 }}</p>
        </li>
        <li class="right" style="padding-right: 70px">
          <h5 style="margin-top: 20px">Add member</h5>
        </li>
        <li class="right">
          <span class="mr-1 plus">
            <font-awesome-icon
              icon="plus"
              style="color: rgb(72, 177, 219); margin-top: 29px"
            />
          </span>
        </li>
      </div>
      <div
        class="container-fluid min-h-screen justify-center mx-auto"
        style="padding-top: 150px"
      >
        <div class="flex pt-180 overflow-auto">
          <div class="inserters"></div>
          <task-table
            v-for="column in columns"
            :key="column.title"
            :column="column"
          ></task-table>
          <button
            class="
              text-gray-700
              font-semibold font-sans
              tracking-wide
              text-xs
              btnn
              button
            "
            @click="showTableModal = true"
          >
            +
          </button>
        </div>
      </div>
      <vueper-slide v-for="i in 4" :key="i" />
    </vueper-slides>
  </div>
</template>

<script>
import { VueperSlides, VueperSlide } from "vueperslides";
import "vueperslides/dist/vueperslides.css";
import draggable from "vuedraggable";
import VueTailwindModal from "vue-tailwind-modal";
import uuid from "uuid-random";
import EventBus from "./eventBus";
import tasklist from "./tasklist.js";
import TaskTable from "./components/Table.vue";
import TableAdder from "./components/TableAdder.vue";
import TaskAdder from "./components/TaskAdder.vue";
import NavBar from "./components/NavBar.vue";
import DashAdder from "./components/DashAdder.vue";
import Dash from "./components/Dash.vue";
export default {
  name: "App",
  components: {
    VueperSlides,
    VueperSlide,
    Dash,
    draggable,
    VueTailwindModal,
    TaskTable,
    TableAdder,
    TaskAdder,
    NavBar,
    DashAdder,
  },
  created() {
    EventBus.$on("removeTask", this.removeTaskEvent);
    EventBus.$on("showTask", this.addTaskEvent);
    EventBus.$on("showDash", this.addDashEvent);
  },
  beforeDestroy() {
    EventBus.$off("removeTask", this.removeTaskEvent);
    EventBus.$off("showTask", this.addTaskEvent);
    EventBus.$off("showDash", this.addDashEvent);
  },
  data() {
    return {
      showDashModal: false,
      showTaskModal: false,
      showTableModal: false,
      columns: tasklist,
      dashes: [],
      teamMembers: [
        { name: 'MH', color: 'rgb(197, 197, 197)' },
        { name: 'JD', color: 'rgb(72, 177, 219)' },
        { name: 'AS', color: 'rgb(255, 193, 7)' },
        // +16 placeholder
      ],
      mainProps: {
        blank: false,
        width: 39,
        height: 39,
        class: "m1",
      },
    };
  },
  methods: {
    addTableEvent(value) {
      this.columns.push({
        title: value,
        tasks: [],
      });
      this.showTableModal = false;
    },
    addDashEvent(value) {
      this.dashes.push({
        title: value,
        columns: [],
      });
      this.showDashModal = false;
    },
    addTaskEvent(value) {
      for (let i = 0; i < this.columns.length; i++) {
        if (this.columns[i].title === value.tableNo) {
          this.columns[i].tasks.push({
            id: uuid(),
            title: value.taskName,
            Description: value.taskDescription,
            type: value.tagName,
            task: parseInt(value.taskQty),
          });
        }
      }
      this.showTaskModal = false;
    },
    removeTaskEvent(value) {
      for (var i = 0; i < this.columns.length; i++) {
        for (var k = 0; k < this.columns[i].tasks.length; k++) {
          if (this.columns[i].tasks[k].id === value.taskId) {
            this.columns[i].tasks.splice(k, 1);
          }
        }
      }
    },
    clearAll() {
      const r = confirm("Please confirm to reset the board!");
      if (r) {
        localStorage.removeItem('tasks');
        this.columns = [{
          title: "Backlog",
          tasks: [],
        }];
        this.dashes = [];
      }
    },
  },
  computed: {
    tables: function () {
      let array = [];
      this.columns.forEach(function (item) {
        array.push(item.title);
      });
      return array;
    },
  },
  watch: {
    showTaskModal(newValue) {
      if (newValue) {
        this.showTableModal = false;
        this.showDashModal = false;
      }
    },
    showDashModal(newValue) {
      if (newValue) {
        this.showTaskModal = false;
        this.showTableModal = false;
      }
    },
    showTableModal(newValue) {
      if (newValue) {
        this.showTaskModal = false;
        this.showDashModal = false;
      }
    },
    columns: {
      handler() {
        localStorage.tasks = JSON.stringify(this.columns);
      },
      deep: true,
    },
  },
  mounted() {
    if (localStorage.getItem("tasks")) {
      this.columns = JSON.parse(localStorage.getItem("tasks"));
    }
    // Persist dashes too
    if (localStorage.getItem("dashes")) {
      this.dashes = JSON.parse(localStorage.getItem("dashes"));
    }
  },
};
</script>

